#!/usr/bin/env bash
# ============================================================
#  Rust RCON Panel — Full Stack Installer v1.9.0
#  Installs: SteamCMD · Rust Server · Oxide · Plugins · Panel
#  Requires: Debian/Ubuntu Linux, root
# ============================================================
set -euo pipefail

VERSION="1.9.0"
STEAM_USER="steam"
STEAM_HOME="/home/steam"
RUST_DIR="${STEAM_HOME}/rustserver"
PANEL_DIR="${STEAM_HOME}/rcon-panel"
STEAMCMD_DIR="${STEAM_HOME}/steamcmd"
SERVICE_PANEL="rust-rcon-panel"
SERVICE_RUST="rust-server"
RUST_APP_ID="258550"

GREEN='\033[0;32m'; CYAN='\033[0;36m'; YELLOW='\033[1;33m'
RED='\033[0;31m'; BOLD='\033[1m'; NC='\033[0m'

ok()    { echo -e "${GREEN}[+]${NC} $*"; }
info()  { echo -e "${CYAN}[*]${NC} $*"; }
warn()  { echo -e "${YELLOW}[!]${NC} $*"; }
err()   { echo -e "${RED}[x]${NC} $*" >&2; }
die()   { err "$*"; exit 1; }
ask()   { local __v=$1 __p=$2 __d=${3:-}
          echo -en "${BOLD}${__p}${NC}"; [ -n "$__d" ] && echo -en " [${CYAN}${__d}${NC}]"
          echo -en ": "; read -r "$__v"
          [ -z "${!__v}" ] && printf -v "$__v" '%s' "$__d"; }
gen_pw(){ openssl rand -base64 18 | tr -d '/+=' | head -c 20; }
gen_seed(){ echo $((RANDOM * RANDOM % 2147483647)); }

banner() {
  echo -e "${RED}"
  echo '  ██████╗ ██╗   ██╗███████╗████████╗    ██████╗  █████╗ ███╗   ██╗███████╗██╗'
  echo '  ██╔══██╗██║   ██║██╔════╝╚══██╔══╝    ██╔══██╗██╔══██╗████╗  ██║██╔════╝██║'
  echo '  ██████╔╝██║   ██║███████╗   ██║       ██████╔╝███████║██╔██╗ ██║█████╗  ██║'
  echo '  ██╔══██╗██║   ██║╚════██║   ██║       ██╔═══╝ ██╔══██║██║╚██╗██║██╔══╝  ██║'
  echo '  ██║  ██║╚██████╔╝███████║   ██║       ██║     ██║  ██║██║ ╚████║███████╗███████╗'
  echo '  ╚═╝  ╚═╝ ╚═════╝ ╚══════╝   ╚═╝       ╚═╝     ╚═╝  ╚═╝╚═╝  ╚═══╝╚══════╝╚══════╝'
  echo -e "${NC}"
  echo -e "  ${BOLD}Full Stack Installer${NC} v${VERSION}"
  echo -e "  Installs: SteamCMD · Rust Dedicated Server · Oxide/uMod · RCON Panel"
  echo
}

# ── Preflight ─────────────────────────────────────────────────────────────────

check_root() {
  [ "$EUID" -eq 0 ] || die "Run as root: sudo bash install.sh"
  ok "Running as root"
}

check_os() {
  if command -v apt-get &>/dev/null; then
    PKG_MGR="apt"
    ok "Package manager: apt"
  else
    die "Unsupported OS — requires Debian/Ubuntu (apt)"
  fi
}

check_python() {
  python3 --version &>/dev/null || die "python3 not found"
  ok "Python3 available"
}

# ── Configuration gathering ───────────────────────────────────────────────────

gather_config() {
  echo
  echo -e "${BOLD}─── Rust Server ─────────────────────────────────────────────${NC}"
  echo

  ask SERVER_NAME "Server hostname (display name)" "My Rust Server"
  ask SERVER_DESC "Server description"              "A Rust server"
  ask SERVER_PORT "Game port"                       "28015"
  ask RCON_PORT   "RCON WebSocket port"             "28016"

  local auto_rcon; auto_rcon=$(gen_pw)
  ask RCON_PASS   "RCON password (blank = auto-generate)" ""
  [ -z "$RCON_PASS" ] && RCON_PASS="$auto_rcon" && info "Auto-generated RCON password: ${BOLD}${RCON_PASS}${NC}"

  ask WORLD_SIZE  "World size (1000–6000)"         "3000"
  local auto_seed; auto_seed=$(gen_seed)
  ask WORLD_SEED  "World seed (blank = random)"    ""
  [ -z "$WORLD_SEED" ] && WORLD_SEED="$auto_seed" && info "Random seed: ${BOLD}${WORLD_SEED}${NC}"
  ask MAX_PLAYERS "Max players"                    "50"

  echo
  echo -e "${BOLD}─── Web Panel ───────────────────────────────────────────────${NC}"
  echo

  ask WEB_PORT    "Web panel port"                 "80"

  local auto_web; auto_web=$(gen_pw)
  ask WEB_PASS    "Panel password (blank = auto-generate)" ""
  [ -z "$WEB_PASS" ] && WEB_PASS="$auto_web" && info "Auto-generated panel password: ${BOLD}${WEB_PASS}${NC}"

  echo
  echo -e "${BOLD}─── Install Paths ───────────────────────────────────────────${NC}"
  echo

  ask RUST_DIR    "Rust server install dir"        "$RUST_DIR"
  ask PANEL_DIR   "Panel install dir"              "$PANEL_DIR"

  echo
  echo -e "${BOLD}─── Summary ─────────────────────────────────────────────────${NC}"
  echo "  Server:        ${SERVER_NAME}"
  echo "  Ports:         game=${SERVER_PORT}  rcon=${RCON_PORT}  panel=${WEB_PORT}"
  echo "  RCON password: ${RCON_PASS}"
  echo "  Panel password: ${WEB_PASS}"
  echo "  World:         size=${WORLD_SIZE}  seed=${WORLD_SEED}  maxplayers=${MAX_PLAYERS}"
  echo "  Rust dir:      ${RUST_DIR}"
  echo "  Panel dir:     ${PANEL_DIR}"
  echo
  ask CONFIRM "Continue? (yes/no)" "yes"
  [[ "$CONFIRM" == "yes" || "$CONFIRM" == "y" ]] || die "Aborted."
}

# ── System dependencies ───────────────────────────────────────────────────────

install_system_deps() {
  info "Installing system dependencies..."
  dpkg --add-architecture i386 2>/dev/null || true
  apt-get update -qq
  apt-get install -y -q \
    curl wget unzip tar \
    lib32gcc-s1 libgdiplus \
    python3 python3-aiohttp python3-cryptography \
    2>/dev/null
  ok "System dependencies installed"
}

# ── Steam user ────────────────────────────────────────────────────────────────

setup_steam_user() {
  if id "$STEAM_USER" &>/dev/null; then
    ok "User '${STEAM_USER}' already exists"
  else
    info "Creating user '${STEAM_USER}'..."
    useradd -m -s /bin/bash "$STEAM_USER"
    ok "User '${STEAM_USER}' created"
  fi
  STEAM_HOME=$(getent passwd "$STEAM_USER" | cut -d: -f6)
  RUST_DIR="${RUST_DIR/#\/home\/steam/$STEAM_HOME}"
  PANEL_DIR="${PANEL_DIR/#\/home\/steam/$STEAM_HOME}"
  STEAMCMD_DIR="${STEAMCMD_DIR/#\/home\/steam/$STEAM_HOME}"
}

# ── SteamCMD ──────────────────────────────────────────────────────────────────

install_steamcmd() {
  if [ -f "${STEAMCMD_DIR}/steamcmd.sh" ]; then
    ok "SteamCMD already installed"
    return
  fi
  info "Installing SteamCMD..."
  mkdir -p "$STEAMCMD_DIR"
  curl -sSL "https://steamcdn-a.akamaihd.net/client/installer/steamcmd_linux.tar.gz" \
    | tar -xz -C "$STEAMCMD_DIR"
  chown -R "${STEAM_USER}:${STEAM_USER}" "$STEAMCMD_DIR"
  ok "SteamCMD installed at ${STEAMCMD_DIR}"
}

# ── Rust dedicated server ─────────────────────────────────────────────────────

install_rust() {
  info "Installing Rust dedicated server (app ${RUST_APP_ID})..."
  info "This may take 10–30 minutes depending on connection speed (~10 GB)..."
  mkdir -p "$RUST_DIR"
  chown "${STEAM_USER}:${STEAM_USER}" "$RUST_DIR"
  su -s /bin/bash "$STEAM_USER" -c \
    "${STEAMCMD_DIR}/steamcmd.sh \
      +force_install_dir \"${RUST_DIR}\" \
      +login anonymous \
      +app_update ${RUST_APP_ID} validate \
      +quit"
  [ -f "${RUST_DIR}/RustDedicated" ] || die "Rust server binary not found after install"
  ok "Rust dedicated server installed"
}

# ── Oxide/uMod ────────────────────────────────────────────────────────────────

install_oxide() {
  info "Installing Oxide/uMod..."
  local oxide_url="https://github.com/OxideMod/Oxide.Rust/releases/latest/download/Oxide.Rust-linux.zip"
  local tmp="/tmp/oxide_rust.zip"
  curl -sSL "$oxide_url" -o "$tmp" || wget -q "$oxide_url" -O "$tmp" \
    || die "Failed to download Oxide"
  unzip -o "$tmp" -d "$RUST_DIR" > /dev/null
  rm -f "$tmp"
  chown -R "${STEAM_USER}:${STEAM_USER}" "$RUST_DIR"
  ok "Oxide/uMod installed"
}

# ── Rust server startup script ────────────────────────────────────────────────

configure_rust_server() {
  info "Writing Rust server startup script..."
  local query_port=$(( SERVER_PORT + 1 ))
  cat > "${RUST_DIR}/start.sh" << STARTSH
#!/bin/bash
cd "${RUST_DIR}"
exec ./RustDedicated \\
  -batchmode \\
  -nographics \\
  -server.ip 0.0.0.0 \\
  -server.port ${SERVER_PORT} \\
  -server.queryport ${query_port} \\
  -rcon.ip 0.0.0.0 \\
  -rcon.port ${RCON_PORT} \\
  -rcon.password "${RCON_PASS}" \\
  -rcon.web 1 \\
  -server.identity my_server_identity \\
  -server.hostname "${SERVER_NAME}" \\
  -server.description "${SERVER_DESC}" \\
  -server.worldsize ${WORLD_SIZE} \\
  -server.seed ${WORLD_SEED} \\
  -server.maxplayers ${MAX_PLAYERS} \\
  +server.saveinterval 300
STARTSH
  chmod +x "${RUST_DIR}/start.sh"
  chown "${STEAM_USER}:${STEAM_USER}" "${RUST_DIR}/start.sh"
  ok "Startup script: ${RUST_DIR}/start.sh"
}

# ── RCON panel ────────────────────────────────────────────────────────────────

deploy_panel() {
  info "Deploying RCON panel to ${PANEL_DIR}..."
  mkdir -p "${PANEL_DIR}/static"

  # ── app.py ───────────────────────────────────────────────────────────────
  python3 -c "
import base64, sys
data = b''''''
sys.stdout.buffer.write(base64.b64decode(data))
" > "${PANEL_DIR}/app.py"
  ok "app.py deployed"

  # ── favicon.svg ──────────────────────────────────────────────────────────
  cat > "${PANEL_DIR}/static/favicon.svg" << 'SVGEOF'
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32">
<rect width="32" height="32" rx="6" fill="#1a1c20"/>
<ellipse cx="16" cy="13" rx="10" ry="10" fill="#4fc3f7"/>
<circle cx="11.5" cy="12" r="2.5" fill="#1a1c20"/>
<circle cx="20.5" cy="12" r="2.5" fill="#1a1c20"/>
<rect x="11.5" y="22" width="3" height="6" rx="1.5" fill="#4fc3f7"/>
<rect x="17.5" y="22" width="3" height="6" rx="1.5" fill="#4fc3f7"/>
<rect x="9.5" y="27" width="13" height="2.5" rx="1.2" fill="#4fc3f7" opacity=".4"/>
</svg>
SVGEOF

  # ── Secure config + encrypted profile ────────────────────────────────────
  local img_path="${RUST_DIR}/oxide/data/MapRenderer/map.png"
  python3 - << PYEOF
import os, json, base64, hashlib
from cryptography.fernet import Fernet

panel_dir  = '${PANEL_DIR}'
rcon_host  = '127.0.0.1'
rcon_port  = ${RCON_PORT}
rcon_pass  = '${RCON_PASS}'
web_port   = ${WEB_PORT}
web_pass   = '${WEB_PASS}'
world_size = ${WORLD_SIZE}
world_seed = ${WORLD_SEED}
img_path   = '${img_path}'
server_name = '${SERVER_NAME}'

# Generate Fernet key
key = Fernet.generate_key()
key_path = os.path.join(panel_dir, '.secret_key')
with open(key_path, 'wb') as f:
    f.write(key)
os.chmod(key_path, 0o600)
fernet = Fernet(key)

# Encrypt RCON password
rcon_enc = 'enc:' + fernet.encrypt(rcon_pass.encode()).decode()

# Hash web panel password
salt = os.urandom(16).hex()
dk   = hashlib.pbkdf2_hmac('sha256', web_pass.encode(), salt.encode(), 260_000)
web_hash = 'pbkdf2:' + salt + ':' + base64.b64encode(dk).decode()

# config.json — no rcon section, no plaintext credentials
config = {
    'web': {'host': '0.0.0.0', 'port': web_port, 'password': web_hash},
    'map': {'world_size': world_size, 'seed': world_seed,
            'image_url': '', 'image_path': img_path}
}
with open(os.path.join(panel_dir, 'config.json'), 'w') as f:
    json.dump(config, f, indent=2)

# profiles.json — encrypted RCON credentials
profile_id = os.urandom(6).hex()
profiles = [{'id': profile_id, 'name': server_name,
             'host': rcon_host, 'port': rcon_port, 'password': rcon_enc}]
with open(os.path.join(panel_dir, 'profiles.json'), 'w') as f:
    json.dump(profiles, f, indent=2)

print('Panel config written (all passwords secured)')
PYEOF

  chown -R "${STEAM_USER}:${STEAM_USER}" "$PANEL_DIR"
  ok "Panel deployed and configured"
}

# ── Oxide plugins ─────────────────────────────────────────────────────────────

deploy_plugins() {
  local plugin_dir="${RUST_DIR}/oxide/plugins"
  mkdir -p "$plugin_dir"

  # ── MapRenderer.cs ───────────────────────────────────────────────────────
  info "Deploying MapRenderer plugin..."
  python3 -c "
import base64, sys
data = b''''''
sys.stdout.buffer.write(base64.b64decode(data))
" > "${plugin_dir}/MapRenderer.cs"

  local map_cfg="${RUST_DIR}/oxide/config/MapRenderer.json"
  local img_path="${RUST_DIR}/oxide/data/MapRenderer/map.png"
  mkdir -p "$(dirname "$map_cfg")" "$(dirname "$img_path")"
  if [ ! -f "$map_cfg" ]; then
    echo "{\"output_path\": \"${img_path}\"}" > "$map_cfg"
  fi
  ok "MapRenderer.cs deployed"

  # ── PlayerLocation.cs ────────────────────────────────────────────────────
  info "Getting PlayerLocation plugin..."
  if curl -fsSL "https://umod.org/plugins/PlayerLocation.cs" \
       -o "${plugin_dir}/PlayerLocation.cs" 2>/dev/null \
     || wget -q "https://umod.org/plugins/PlayerLocation.cs" \
       -O "${plugin_dir}/PlayerLocation.cs" 2>/dev/null; then
    ok "PlayerLocation.cs downloaded"
  else
    warn "Download failed — embedding bundled version"
    cat > "${plugin_dir}/PlayerLocation.cs" << 'PLOC_EOF'
using System;
using System.Collections.Generic;
using Oxide.Core;
using Oxide.Core.Libraries.Covalence;
using UnityEngine;

namespace Oxide.Plugins
{
    [Info("Player Location", "seacowz", "0.1.7")]
    [Description("Find the location of players on the server")]
    public class PlayerLocation : CovalencePlugin
    {
        private const string permAdmin = "playerlocation.admin";
        void Init() { permission.RegisterPermission(permAdmin, this); }

        [Command("location"), Permission("playerlocation.admin")]
        void CmdLocation(IPlayer iplayer, string command, string[] args)
        {
            bool any = false;
            foreach (var p in players.Connected)
            {
                var bp = p.Object as BasePlayer;
                if (bp == null) continue;
                var pos = bp.transform.position;
                var grid = PhoneController.PositionToGridCoord(pos);
                iplayer.Reply($"{p.Id} {p.Name}: {grid}, {pos.x:F1}, {pos.z:F1}");
                any = true;
            }
            if (!any) iplayer.Reply("No players found.");
        }
    }
}
PLOC_EOF
  fi

  chown -R "${STEAM_USER}:${STEAM_USER}" "$RUST_DIR"
}

# ── Systemd services ──────────────────────────────────────────────────────────

install_services() {
  info "Installing systemd services..."

  # Rust dedicated server
  cat > "/etc/systemd/system/${SERVICE_RUST}.service" << SVC
[Unit]
Description=Rust Dedicated Game Server
After=network.target

[Service]
Type=simple
User=${STEAM_USER}
Group=${STEAM_USER}
WorkingDirectory=${RUST_DIR}
ExecStart=${RUST_DIR}/start.sh
Restart=on-failure
RestartSec=30
KillSignal=SIGINT
TimeoutStopSec=120
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
SVC

  # RCON panel
  cat > "/etc/systemd/system/${SERVICE_PANEL}.service" << SVC
[Unit]
Description=Rust RCON Web Panel
After=network.target

[Service]
Type=simple
WorkingDirectory=${PANEL_DIR}
ExecStart=/usr/bin/python3 ${PANEL_DIR}/app.py
Restart=always
RestartSec=5
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
SVC

  systemctl daemon-reload
  systemctl enable "${SERVICE_RUST}"  2>/dev/null
  systemctl enable "${SERVICE_PANEL}" 2>/dev/null

  info "Starting RCON panel..."
  systemctl restart "${SERVICE_PANEL}"
  sleep 2
  systemctl is-active "${SERVICE_PANEL}" >/dev/null \
    && ok "Panel service started" \
    || { err "Panel failed to start"; journalctl -u "${SERVICE_PANEL}" -n 20 --no-pager; exit 1; }

  info "Starting Rust server (this takes ~60s on first boot)..."
  systemctl start "${SERVICE_RUST}" || warn "Rust server start queued (may take time)"
  ok "Services installed and enabled"
}

# ── Oxide permissions ─────────────────────────────────────────────────────────

grant_oxide_permissions() {
  info "Waiting for Rust server RCON to come up (up to 90s)..."
  local attempts=18
  local granted=false
  for i in $(seq 1 $attempts); do
    sleep 5
    if python3 -c "
import asyncio, aiohttp
async def run():
    try:
        async with aiohttp.ClientSession() as s:
            async with s.ws_connect('ws://127.0.0.1:${RCON_PORT}/${RCON_PASS}',
                timeout=aiohttp.ClientTimeout(connect=3)) as ws:
                for i, cmd in enumerate([
                    'oxide.grant group admin playerlocation.admin',
                ], 1):
                    await ws.send_json({'Identifier': i, 'Message': cmd, 'Name': 'Installer'})
                    await asyncio.sleep(0.5)
        print('ok')
    except: print('fail')
asyncio.run(run())
" 2>/dev/null | grep -q "ok"; then
      ok "Oxide permissions granted"
      granted=true
      break
    fi
    echo -en "  Waiting... (${i}/${attempts})\r"
  done
  if [ "$granted" = false ]; then
    warn "Could not reach RCON — server may still be loading."
    warn "Run manually once server is up: oxide.grant group admin playerlocation.admin"
  fi
}

# ── Summary ───────────────────────────────────────────────────────────────────

print_summary() {
  local ip; ip=$(hostname -I | awk '{print $1}')
  echo
  echo -e "${GREEN}═══════════════════════════════════════════════════════════${NC}"
  echo -e "${GREEN}  Installation complete — v${VERSION}${NC}"
  echo -e "${GREEN}═══════════════════════════════════════════════════════════${NC}"
  echo
  echo -e "  ${BOLD}RCON Panel:${NC}      http://${ip}:${WEB_PORT}"
  echo -e "  ${BOLD}Panel password:${NC}  ${WEB_PASS}"
  echo
  echo -e "  ${BOLD}Rust Server:${NC}     ${ip}:${SERVER_PORT}"
  echo -e "  ${BOLD}RCON port:${NC}       ${RCON_PORT}"
  echo -e "  ${BOLD}RCON password:${NC}   ${RCON_PASS}"
  echo -e "  ${BOLD}World:${NC}           size=${WORLD_SIZE}  seed=${WORLD_SEED}  maxplayers=${MAX_PLAYERS}"
  echo
  echo -e "  ${BOLD}Startup script:${NC}  ${RUST_DIR}/start.sh"
  echo
  echo -e "  ${BOLD}Service commands:${NC}"
  echo -e "    systemctl status ${SERVICE_PANEL}   # panel"
  echo -e "    systemctl status ${SERVICE_RUST}    # rust server"
  echo -e "    journalctl -u ${SERVICE_PANEL} -f"
  echo -e "    journalctl -u ${SERVICE_RUST} -f"
  echo
  echo -e "  ${CYAN}Note:${NC} Map renders ~10s after server starts."
  echo -e "        Use ${BOLD}📷 Re-render${NC} in the Map tab to force a refresh."
  echo
}

# ── Main ──────────────────────────────────────────────────────────────────────

main() {
  banner
  check_root
  check_os
  check_python
  gather_config
  install_system_deps
  setup_steam_user
  install_steamcmd
  install_rust
  install_oxide
  configure_rust_server
  deploy_panel
  deploy_plugins
  install_services
  grant_oxide_permissions
  print_summary
}

main "$@"
